<!doctype html><html><head><meta charset="utf-8"><style>body{font-family:DejaVu Sans,sans-serif;font-size:10px;color:#202938}h1{font-size:20px}h2{font-size:14px;border-bottom:1px solid #999;padding-bottom:3px;margin-top:18px}table{width:100%;border-collapse:collapse}th,td{padding:4px;border-bottom:1px solid #ddd;text-align:left;vertical-align:top}.muted{color:#666}.page-break{page-break-before:always}</style></head><body>
<h1>TheraConnect Longitudinal Patient Record</h1><p class="muted">Generated {{ now()->format('M d, Y h:i A') }} · Confidential clinical information</p>
<h2>Patient Profile</h2><table><tr><th>Name</th><td>{{ $patient->user->name }}</td><th>Email</th><td>{{ $patient->user->email }}</td></tr><tr><th>Date of birth</th><td>{{ $patient->date_of_birth?->format('M d, Y') ?? 'Not recorded' }}</td><th>Contact</th><td>{{ $patient->contact_no ?? 'Not recorded' }}</td></tr><tr><th>Address</th><td colspan="3">{{ $patient->address ?? 'Not recorded' }}</td></tr><tr><th>Personal issues</th><td colspan="3">{{ $patient->personal_issues ?? 'Not recorded' }}</td></tr><tr><th>Intake notes</th><td colspan="3">{{ $patient->notes ?? 'Not recorded' }}</td></tr></table>
