<h2>Assessments</h2><table><tr><th>Date</th><th>Instrument</th><th>Status</th><th>Score</th><th>Responses</th></tr>@forelse($patient->assessments->sortByDesc('created_at') as $item)<tr><td>{{ $item->completed_at?->format('M d, Y') ?? $item->created_at->format('M d, Y') }}</td><td>{{ $item->title() }}</td><td>{{ ucfirst($item->status) }}</td><td>{{ $item->score ?? '-' }}</td><td>{{ collect($item->responses ?? [])->map(fn($v,$k) => $k.': '.$v)->implode('; ') }}</td></tr>@empty<tr><td colspan="5">No assessments</td></tr>@endforelse</table>
<h2>Goals</h2>@forelse($patient->therapyGoals as $goal)<p><strong>{{ $goal->description }}</strong> ({{ ucfirst($goal->status) }})<br>Target: {{ $goal->target_date?->format('M d, Y') ?? 'None' }}; Ratings: {{ $goal->ratings->map(fn($r) => $r->rating.' on '.$r->created_at->format('M d, Y'))->implode(', ') ?: 'None' }}</p>@empty<p>None recorded</p>@endforelse
<h2>Assignments and Submissions</h2>@forelse($patient->assignments as $assignment)<p><strong>{{ $assignment->title }}</strong> · Due {{ $assignment->due_date?->format('M d, Y') ?? 'not set' }}<br>{{ $assignment->description }}<br>Worksheet: {{ $assignment->attachment_name ?? 'None' }}@foreach($assignment->submissions as $submission)<br>Submission {{ $submission->submitted_at?->format('M d, Y h:i A') }}: {{ $submission->content ?: 'No text' }}; File: {{ $submission->original_name ?? 'None' }}@endforeach</p>@empty<p>None recorded</p>@endforelse
<h2>Mood Check-ins</h2><table><tr><th>Date</th><th>Mood</th><th>Note</th></tr>@forelse($patient->moodLogs->sortByDesc('logged_at') as $mood)<tr><td>{{ ($mood->logged_at ?? $mood->created_at)->format('M d, Y h:i A') }}</td><td>{{ $mood->mood ?? $mood->rating }}</td><td>{{ $mood->note }}</td></tr>@empty<tr><td colspan="3">No mood check-ins</td></tr>@endforelse</table>
